@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="settings-sidebar-title">Settings</h5>
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li class="settings-nav-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="settings-nav-icon">@GetIcon(section)</span>
                <span>@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@using sv_1d976754ae9c4ba38ea59e86c15054ed.Services

<div class="settings-section">
    <h3>Profile</h3>

    <div class="profile-avatar-area">
        @if (!string.IsNullOrWhiteSpace(AvatarUrl))
        {
            <img src="@AvatarUrl" alt="Avatar" class="avatar-preview" />
        }
        else
        {
            <div class="avatar-placeholder">No avatar</div>
        }
        <div class="avatar-url-display">
            <label>Avatar URL</label>
            <input type="text" class="form-control form-control-sm" value="@AvatarUrl" disabled />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="3" @bind="Bio"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string Bio = "";
    private string AvatarUrl = "";
    private string? _statusMessage;
    private bool _isError;
    private bool _saving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_saving)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        Bio = p.Bio;
        AvatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Error saving profile: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        _statusMessage = null;
    }
}

@using sv_1d976754ae9c4ba38ea59e86c15054ed.Services

<div class="settings-section">
    <h3>Notifications</h3>

    <div class="mb-3">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <hr />

    <h5>Muted Channels</h5>
    <div class="channel-list mb-3">
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="ch-@channel"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="ch-@channel">@channel</label>
            </div>
        }
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @(_saving ? "Saving..." : "Save Preferences")
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private string? _statusMessage;
    private bool _saving;

    private static readonly string[] AllChannels = ["general", "announcements", "marketing", "engineering", "design"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_saving)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Notification preferences saved!";
        _saving = false;
    }
}

@* Expandable change password panel *@

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") mb-3">@_message</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_updating">
                @(_updating ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _updating;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "All password fields are required.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _updating = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Error: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _updating = false;
        }
    }
}

@* Confirmation dialog for revoking a session *@

@if (Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@DeviceName</strong>?</p>
                    <p class="text-muted">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string DeviceName { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_1d976754ae9c4ba38ea59e86c15054ed.Services

<div class="settings-section">
    <h3>Security</h3>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@TwoFactorEnabled"
                       @onchange="e => TwoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @if (LastPasswordChange.HasValue)
    {
        <p class="text-muted small">Last password change: @LastPasswordChange.Value.ToString("MMMM d, yyyy")</p>
    }

    <h5>Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @if (Sessions is not null)
                {
                    @foreach (var (session, index) in Sessions.Select((s, i) => (s, i)))
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (index == 0)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         DeviceName="@(_sessionToRevoke?.Device ?? "")"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool TwoFactorEnabled;
    private DateTime? LastPasswordChange;
    private List<ActiveSession>? Sessions;

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            TwoFactorEnabled = Security.TwoFactorEnabled;
            LastPasswordChange = Security.LastPasswordChange;
            Sessions = Security.Sessions;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_1d976754ae9c4ba38ea59e86c15054ed.Services

<div class="settings-section">
    <h3>Appearance</h3>

    <div class="mb-3">
        <label class="form-label fw-bold">Theme</label>
        <div class="d-flex gap-3">
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                           value="@theme" checked="@(Theme == theme)"
                           @onchange="() => Theme = theme" />
                    <label class="form-check-label" for="theme-@theme">@theme</label>
                </div>
            }
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Font Size</label>
        <div class="d-flex gap-3">
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                           value="@size" checked="@(FontSize == size)"
                           @onchange="() => FontSize = size" />
                    <label class="form-check-label" for="fs-@size">@size</label>
                </div>
            }
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold" for="language-select">Language</label>
        <select class="form-select" id="language-select" @bind="Language">
            <option value="English">English</option>
            <option value="Spanish">Spanish</option>
            <option value="French">French</option>
            <option value="German">German</option>
            <option value="Japanese">Japanese</option>
            <option value="Portuguese">Portuguese</option>
        </select>
    </div>

    <div class="mb-3">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
    </div>

    <hr />

    <h5>Preview</h5>
    <div class="appearance-preview @GetPreviewClasses()">
        <div class="preview-header">Sample Header</div>
        <p class="preview-body">
            This is how your content will look with the selected settings.
            The quick brown fox jumps over the lazy dog.
        </p>
        <button class="preview-button">Sample Button</button>
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert alert-success mt-3 alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <button class="btn btn-primary mt-3" @onclick="SaveAsync" disabled="@_saving">
        @(_saving ? "Saving..." : "Save")
    </button>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
