{"file_text": "@using sv_1d976754ae9c4ba38ea59e86c15054ed.Services

<div class="settings-section">
    <h3>Security</h3>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@TwoFactorEnabled"
                       @onchange="e => TwoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @if (LastPasswordChange.HasValue)
    {
        <p class="text-muted small">Last password change: @LastPasswordChange.Value.ToString("MMMM d, yyyy")</p>
    }

    <h5>Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @if (Sessions is not null)
                {
                    @foreach (var (session, index) in Sessions.Select((s, i) => (s, i)))
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (index == 0)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         DeviceName="@(_sessionToRevoke?.Device ?? "")"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool TwoFactorEnabled;
    private DateTime? LastPasswordChange;
    private List<ActiveSession>? Sessions;

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            TwoFactorEnabled = Security.TwoFactorEnabled;
            LastPasswordChange = Security.LastPasswordChange;
            Sessions = Security.Sessions;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
